      keywords: ["right ventricular MI paramedic", "RVMI management", "V4R right sided ECG", "inferior STEMI right ventricle", "nitroglycerin contraindication"],
      related: ["acute-myocardial-infarction", "stemi-recognition-and-management", "twelve-lead-ecg-interpretation", "cardiogenic-shock"]
